'use client'

import { useMemo, useState } from 'react'
import CalculatorShell from '../../../components/CalculatorShell'
import FormField from '../../../components/FormField'

export default function SIPCalculator() {
  const [monthly, setMonthly] = useState(25000)
  const [rate, setRate] = useState(12)
  const [years, setYears] = useState(10)
  const [result, setResult] = useState<number | null>(null)

  const invested = useMemo(() => monthly * 12 * years, [monthly, years])
  const returns = result !== null ? Math.max(0, result - invested) : 0
  const progress = useMemo(() => {
    if (result === null || result === 0) return 0
    return Math.min(100, Math.round((returns / result) * 100))
  }, [returns, result])

  function calculate() {
    const P = monthly
    const r = rate / 100 / 12
    const n = years * 12
    if (!P || !n) return setResult(0)
    if (r === 0) return setResult(P * n)
    const maturity = P * (Math.pow(1 + r, n) - 1) / r * (1 + r)
    setResult(maturity)
  }

  function reset() {
    setMonthly(25000)
    setRate(12)
    setYears(10)
    setResult(null)
  }

  return (
    <CalculatorShell title="SIP Calculator" description="Calculate expected maturity for monthly SIPs.">
      <div className="rounded-3xl border border-slate-200 bg-slate-50 p-6 shadow-sm dark:border-slate-700 dark:bg-slate-950">
        <div className="grid gap-8 xl:grid-cols-[1.15fr_0.85fr]">
          <div className="space-y-6">
            <FormField label="Monthly investment">
              <div className="flex items-center justify-between gap-4">
                <span className="text-sm text-slate-500 dark:text-slate-400">₹{monthly.toLocaleString()}</span>
                <span className="rounded-full bg-emerald-100 px-3 py-1 text-sm font-semibold text-emerald-700 dark:bg-emerald-900/40 dark:text-emerald-200">
                  ₹{monthly.toLocaleString()}
                </span>
              </div>
              <input
                type="range"
                min={1000}
                max={100000}
                step={500}
                value={monthly}
                onChange={(e) => setMonthly(Number(e.target.value))}
                className="slider mt-4"
              />
            </FormField>

            <FormField label="Expected return rate (p.a.)">
              <div className="flex items-center justify-between gap-4">
                <span className="text-sm text-slate-500 dark:text-slate-400">{rate.toFixed(1)}%</span>
                <span className="rounded-full bg-sky-100 px-3 py-1 text-sm font-semibold text-sky-700 dark:bg-sky-900/30 dark:text-sky-200">
                  {rate.toFixed(1)}%
                </span>
              </div>
              <input
                type="range"
                min={1}
                max={25}
                step={0.1}
                value={rate}
                onChange={(e) => setRate(Number(e.target.value))}
                className="slider mt-4"
              />
            </FormField>

            <FormField label="Time period">
              <div className="flex items-center justify-between gap-4">
                <span className="text-sm text-slate-500 dark:text-slate-400">{years} yr{years === 1 ? '' : 's'}</span>
                <span className="rounded-full bg-slate-100 px-3 py-1 text-sm font-semibold text-slate-700 dark:bg-slate-800 dark:text-slate-200">
                  {years} years
                </span>
              </div>
              <input
                type="range"
                min={1}
                max={30}
                step={1}
                value={years}
                onChange={(e) => setYears(Number(e.target.value))}
                className="slider mt-4"
              />
            </FormField>

            <div className="flex flex-col gap-3 sm:flex-row">
              <button onClick={calculate} className="btn-primary w-full sm:w-auto">Calculate</button>
              <button onClick={reset} className="btn-secondary w-full sm:w-auto">Reset</button>
            </div>
          </div>

          <div className="rounded-[28px] border border-slate-200 bg-white p-6 shadow-sm dark:border-slate-700 dark:bg-slate-950">
            <div className="flex items-center justify-between gap-4">
              <div>
                <p className="text-sm font-semibold uppercase tracking-[0.18em] text-slate-500 dark:text-slate-400">Projected value</p>
                <p className="mt-3 text-3xl font-semibold text-slate-900 dark:text-slate-100">
                  {result !== null ? `₹${result.toFixed(0).toLocaleString()}` : '—'}
                </p>
              </div>
              <button className="btn-primary px-4 py-2 text-sm">Invest Now</button>
            </div>

            <div className="mt-8 flex items-center justify-center">
              <div className="relative h-52 w-52">
                <svg viewBox="0 0 120 120" className="h-full w-full">
                  <circle cx="60" cy="60" r="44" className="text-slate-200" strokeWidth="18" fill="none" />
                  <circle
                    cx="60"
                    cy="60"
                    r="44"
                    strokeLinecap="round"
                    className="text-sky-600"
                    strokeWidth="18"
                    fill="none"
                    strokeDasharray={`${progress} ${100 - progress}`}
                    strokeDashoffset="25"
                    transform="rotate(-90 60 60)"
                  />
                </svg>
                <div className="absolute inset-0 flex flex-col items-center justify-center text-center">
                  <span className="text-sm uppercase tracking-[0.18em] text-slate-400 dark:text-slate-500">Returns</span>
                  <span className="mt-2 text-3xl font-semibold text-slate-900 dark:text-slate-100">
                    {result !== null ? `${progress}%` : '0%'}
                  </span>
                </div>
              </div>
            </div>

            <div className="mt-8 space-y-4 text-sm text-slate-700 dark:text-slate-300">
              <div className="flex items-center justify-between gap-4">
                <div className="flex items-center gap-2">
                  <span className="h-2.5 w-2.5 rounded-full bg-slate-300 dark:bg-slate-600" />
                  Invested amount
                </div>
                <span className="font-semibold">₹{invested.toLocaleString()}</span>
              </div>
              <div className="flex items-center justify-between gap-4">
                <div className="flex items-center gap-2">
                  <span className="h-2.5 w-2.5 rounded-full bg-sky-600" />
                  Est. returns
                </div>
                <span className="font-semibold">₹{result !== null ? returns.toFixed(0).toLocaleString() : '0'}</span>
              </div>
              <div className="flex items-center justify-between gap-4">
                <div className="flex items-center gap-2">
                  <span className="h-2.5 w-2.5 rounded-full bg-slate-200 dark:bg-slate-800" />
                  Total value
                </div>
                <span className="font-semibold">{result !== null ? `₹${result.toFixed(0).toLocaleString()}` : '—'}</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </CalculatorShell>
  )
}
