'use client'

export default function CalculatorShell({ title, description, children }: { title: string; description: string; children: React.ReactNode }) {
  return (
    <main className="container mx-auto p-4">
      <section className="panel p-8">
        <div className="mb-6 flex flex-col gap-4 sm:flex-row sm:items-end sm:justify-between">
          <div>
            <h1 className="text-3xl font-bold tracking-tight">{title}</h1>
            <p className="mt-3 max-w-2xl text-slate-600 dark:text-slate-300">{description}</p>
          </div>
          <div className="rounded-3xl bg-slate-100 px-4 py-3 text-sm font-semibold text-slate-700 shadow-sm dark:bg-slate-800 dark:text-slate-200">
            Quick tool — easy results
          </div>
        </div>

        <div className="grid gap-8 lg:grid-cols-[1.4fr_0.9fr]">
          <div className="space-y-6">{children}</div>
          <aside className="rounded-3xl border border-slate-200 bg-white p-6 shadow-sm dark:border-slate-700 dark:bg-slate-950">
            <h2 className="text-xl font-semibold">How it works</h2>
            <p className="mt-3 text-sm leading-7 text-slate-600 dark:text-slate-300">
              Enter values above, then click calculate to instantly see results. For best accuracy, use numeric input only.
            </p>
            <div className="mt-6 space-y-3 text-sm text-slate-700 dark:text-slate-300">
              <p>• Use whole numbers or decimals.</p>
              <p>• Reset anytime to clear inputs.</p>
              <p>• Results update instantly after calculation.</p>
            </div>
          </aside>
        </div>
      </section>
    </main>
  )
}
